from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister
from qiskit_aer import AerSimulator

def base():
    qr = QuantumRegister(1, 'q'); cr = ClassicalRegister(1, 'c')
    qc = QuantumCircuit(qr, cr); qc.h(0); qc.measure(0, 0)
    return qc, cr

# reproduce the bug
qc, cr = base()
try:
    qc.x(0).c_if(cr, 1)
    bug = "no error"
except AttributeError as e:
    bug = f"AttributeError: {str(e)[:70]}"

# candidate fixes
def try_fix(fn):
    try:
        qc, cr = base()
        fn(qc, cr)
        return ("if_else" in qc.count_ops()), f"ops={dict(qc.count_ops())}"
    except Exception as e:
        return False, f"raised {type(e).__name__}: {str(e)[:80]}"

def fixA(qc, cr):
    with qc.if_test((cr, 1)):
        qc.x(0)
def fixB(qc, cr):
    qc.x(0).c_if(cr[0], 1)
def fixC(qc, cr):
    qc2 = qc.decompose(); qc2.x(0).c_if(cr, 1)
def fixD(qc, cr):
    qc.x(0, condition=(cr, 1))

a_ok, a_msg = try_fix(fixA)
b_ok, b_msg = try_fix(fixB)
c_ok, c_msg = try_fix(fixC)
d_ok, d_msg = try_fix(fixD)
claims = {"A": a_ok, "B": b_ok, "C": c_ok, "D": d_ok}
evidence = {
    "A": f"bug={bug}; fix with if_test -> {a_msg} -> valid conditional {a_ok}",
    "B": f"c_if(cr[0],1) -> {b_msg} -> {b_ok}",
    "C": f"decompose then c_if -> {c_msg} -> {c_ok}",
    "D": f"x(0, condition=...) -> {d_msg} -> {d_ok}",
}
proven = [k for k, v in claims.items() if v]
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"bug": bug}})
